# Loop through the array and download each image
for item in "${IMAGES[@]}"; do
    read -r url filename <<< "$item" # Split the item into url and filename
    echo "Downloading $url to $DOWNLOAD_DIR/$filename"
    curl -o "$DOWNLOAD_DIR/$filename" "$url"
done

echo "Image download complete."